41	export const isUndefined = (obj: any): obj is undefined => typeof obj === 'undefined';
42	
43	export const isObject = (fn: any): fn is object => !isNil(fn) && typeof fn === 'object';
44	
45	export const isPlainObject = (fn: any): fn is object => {
46		if (!isObject(fn)) {
47			return false;
48		}
49		const proto = Object.getPrototypeOf(fn);
50		if (proto === null) {
51			return true;
52		}
53		const ctor =
54			Object.prototype.hasOwnProperty.call(proto, 'constructor') && proto.constructor;
55		return (
56			typeof ctor === 'function' &&
57			ctor instanceof ctor &&
58			Function.prototype.toString.call(ctor) === Function.prototype.toString.call(Object)
59		);
60	};
