62	export const addLeadingSlash = (path?: string): string =>
63		path && typeof path === 'string'
64			? path.charAt(0) !== '/' && path.substring(0, 2) !== '{/'
65				? '/' + path
66				: path
67			: '';
68	
69	export const normalizePath = (path?: string): string =>
70		path
71			? path.startsWith('/')
72				? ('/' + path.replace(/\/+$/, '')).replace(/\/+/g, '/')
73				: '/' + path.replace(/\/+$/, '')
74			: '/';
75	
76	export const stripEndSlash = (path: string): string =>
77		path.endsWith('/') ? path.slice(0, -1) : path;
78	
79	export const isFunction = (val: unknown): val is Function => typeof val === 'function';
80	export const isString = (val: any): val is string => typeof val === 'string';
81	export const isNumber = (val: any): val is number => typeof val === 'number';
82	export const isConstructor = (val: any): boolean => val === 'constructor';
83	export const isNil = (val: any): val is null | undefined =>
84		isUndefined(val) || val === null;
85	export const isEmpty = (array: any): boolean => !(array && array.length > 0);
86	export const isSymbol = (val: any): val is symbol => typeof val === 'symbol';
