124	@Injectable()
125	export class AppConsoleLogger implements LoggerService {
126		protected options: ConsoleLoggerOptions;
127		protected context?: string;
128		protected originalContext?: string;
129		protected inspectOptions: InspectOptions;
130		protected static lastTimestampAt?: number;
131	
132		constructor();
133		constructor(context: string);
134		constructor(options: ConsoleLoggerOptions);
135		constructor(context: string, options: ConsoleLoggerOptions);
136		constructor(
137			@Optional()
138			contextOrOptions?: string | ConsoleLoggerOptions,
139			@Optional()
140			options?: ConsoleLoggerOptions,
141		) {
142			let [context, opts] = isString(contextOrOptions)
143				? [contextOrOptions, options]
144				: options
145					? [undefined, options]
146					: [contextOrOptions?.context, contextOrOptions];
147	
148			opts = opts ?? {};
149			opts.logLevels ??= DEFAULT_LOG_LEVELS;
150			opts.colors ??= opts.colors ?? (opts.json ? false : true);
151			opts.prefix ??= 'Nest';
152	
153			this.options = opts;
154			this.inspectOptions = this.getInspectOptions();
155	
156			if (context) {
157				this.context = context;
158				this.originalContext = context;
159			}
160		}
