162		log(message: any, context?: string): void;
163		log(message: any, ...optionalParams: [...any, string?]): void;
164		log(message: any, ...optionalParams: any[]) {
165			if (!this.isLevelEnabled('log')) {
166				return;
167			}
168			const { messages, context } = this.getContextAndMessagesToPrint([
169				message,
170				...optionalParams,
171			]);
172			this.printMessages(messages, context, 'log');
173		}
174	
175		error(message: any, stackOrContext?: string): void;
176		error(message: any, stack?: string, context?: string): void;
177		error(message: any, ...optionalParams: [...any, string?, string?]): void;
178		error(message: any, ...optionalParams: any[]) {
179			if (!this.isLevelEnabled('error')) {
180				return;
181			}
182			const { messages, context, stack } = this.getContextAndStackAndMessagesToPrint([
183				message,
184				...optionalParams,
185			]);
186	
187			this.printMessages(messages, context, 'error', 'stderr', stack);
188			this.printStackTrace(stack!);
189		}
