/* eslint-disable */
import {
	AppConsoleLogger,
	isLogLevelEnabled,
	isUndefined,
	isObject,
	isPlainObject,
	addLeadingSlash,
	normalizePath,
	stripEndSlash,
	isFunction,
	isString,
	isNumber,
	isConstructor,
	isNil,
	isEmpty,
	isSymbol,
} from '@config/custom-logger.config';

jest.mock('correlation-id-ts', () => ({
	correlator: {
		getId: jest.fn(),
	},
}));

jest.mock('node:crypto', () => ({
	...jest.requireActual('node:crypto'),
	randomUUID: jest.fn().mockReturnValue('fallback-uuid'),
}));

import { correlator } from 'correlation-id-ts';

describe('isLogLevelEnabled', () => {
	it('should return false when logLevels is undefined', () => {
		expect(isLogLevelEnabled('log', undefined)).toBe(false);
	});

	it('should return false when logLevels is empty array', () => {
		expect(isLogLevelEnabled('log', [])).toBe(false);
	});

	it('should return true when targetLevel is explicitly in logLevels', () => {
		expect(isLogLevelEnabled('log', ['log', 'error'])).toBe(true);
	});

	it('should return true when targetLevel is higher than highest enabled level', () => {
		expect(isLogLevelEnabled('error', ['log'])).toBe(true);
	});

	it('should return false when targetLevel is lower than highest enabled level', () => {
		expect(isLogLevelEnabled('verbose', ['log'])).toBe(false);
	});

	it('should return true for fatal when warn is highest enabled', () => {
		expect(isLogLevelEnabled('fatal', ['warn'])).toBe(true);
	});

	it('should return true when all levels are enabled and level matches', () => {
		expect(isLogLevelEnabled('debug', ['verbose', 'debug', 'log', 'warn', 'error', 'fatal'])).toBe(true);
	});

	it('should return true for verbose when verbose is explicitly included', () => {
		expect(isLogLevelEnabled('verbose', ['verbose'])).toBe(true);
	});

	it('should return false for debug when only error is enabled', () => {
		expect(isLogLevelEnabled('debug', ['error'])).toBe(false);
	});

	it('should correctly sort multiple levels and pick highest', () => {
		expect(isLogLevelEnabled('warn', ['verbose', 'debug'])).toBe(true);
	});
});

describe('Helper functions', () => {
	describe('isUndefined', () => {
		it('should return true for undefined', () => {
			expect(isUndefined(undefined)).toBe(true);
		});

		it('should return false for null', () => {
			expect(isUndefined(null)).toBe(false);
		});

		it('should return false for 0', () => {
			expect(isUndefined(0)).toBe(false);
		});

		it('should return false for empty string', () => {
			expect(isUndefined('')).toBe(false);
		});

		it('should return false for false', () => {
			expect(isUndefined(false)).toBe(false);
		});

		it('should return false for object', () => {
			expect(isUndefined({})).toBe(false);
		});
	});

	describe('isObject', () => {
		it('should return true for plain object', () => {
			expect(isObject({})).toBe(true);
		});

		it('should return true for array', () => {
			expect(isObject([])).toBe(true);
		});

		it('should return true for class instance', () => {
			expect(isObject(new Date())).toBe(true);
		});

		it('should return false for null', () => {
			expect(isObject(null)).toBe(false);
		});

		it('should return false for string', () => {
			expect(isObject('string')).toBe(false);
		});

		it('should return false for number', () => {
			expect(isObject(42)).toBe(false);
		});

		it('should return false for undefined', () => {
			expect(isObject(undefined)).toBe(false);
		});
	});

	describe('isPlainObject', () => {
		it('should return true for object literal', () => {
			expect(isPlainObject({ key: 'value' })).toBe(true);
		});

		it('should return true for Object.create(null)', () => {
			expect(isPlainObject(Object.create(null))).toBe(true);
		});

		it('should return false for array', () => {
			expect(isPlainObject([])).toBe(false);
		});

		it('should return false for class instance', () => {
			expect(isPlainObject(new Date())).toBe(false);
		});

		it('should return false for null', () => {
			expect(isPlainObject(null)).toBe(false);
		});

		it('should return false for string', () => {
			expect(isPlainObject('string')).toBe(false);
		});

		it('should return false for function', () => {
			expect(isPlainObject(() => {})).toBe(false);
		});
	});

	describe('addLeadingSlash', () => {
		it('should add leading slash to path without one', () => {
			expect(addLeadingSlash('foo')).toBe('/foo');
		});

		it('should not add slash when path already starts with /', () => {
			expect(addLeadingSlash('/foo')).toBe('/foo');
		});

		it('should not add slash when path starts with {/', () => {
			expect(addLeadingSlash('{/foo}')).toBe('{/foo}');
		});

		it('should return empty string for undefined', () => {
			expect(addLeadingSlash(undefined)).toBe('');
		});

		it('should return empty string for empty string', () => {
			expect(addLeadingSlash('')).toBe('');
		});
	});

	describe('normalizePath', () => {
		it('should return / for undefined', () => {
			expect(normalizePath(undefined)).toBe('/');
		});

		it('should return / for empty string', () => {
			expect(normalizePath('')).toBe('/');
		});

		it('should normalize path with leading slash', () => {
			expect(normalizePath('/foo/bar')).toBe('/foo/bar');
		});

		it('should add leading slash if missing', () => {
			expect(normalizePath('foo/bar')).toBe('/foo/bar');
		});

		it('should remove trailing slash', () => {
			expect(normalizePath('/foo/bar/')).toBe('/foo/bar');
		});

		it('should collapse double slashes', () => {
			expect(normalizePath('//foo//bar')).toBe('/foo/bar');
		});

		it('should handle path without leading slash and trailing slash', () => {
			expect(normalizePath('foo/')).toBe('/foo');
		});
	});

	describe('stripEndSlash', () => {
		it('should remove trailing slash', () => {
			expect(stripEndSlash('/foo/')).toBe('/foo');
		});

		it('should not modify path without trailing slash', () => {
			expect(stripEndSlash('/foo')).toBe('/foo');
		});

		it('should strip single trailing slash from root', () => {
			expect(stripEndSlash('/')).toBe('');
		});
	});

	describe('isFunction', () => {
		it('should return true for function', () => {
			expect(isFunction(() => {})).toBe(true);
		});

		it('should return true for named function', () => {
			expect(isFunction(function named() {})).toBe(true);
		});

		it('should return true for class constructor', () => {
			expect(isFunction(class MyClass {})).toBe(true);
		});

		it('should return false for string', () => {
			expect(isFunction('not a function')).toBe(false);
		});

		it('should return false for object', () => {
			expect(isFunction({})).toBe(false);
		});

		it('should return false for null', () => {
			expect(isFunction(null)).toBe(false);
		});
	});

	describe('isString', () => {
		it('should return true for string primitive', () => {
			expect(isString('hello')).toBe(true);
		});

		it('should return true for empty string', () => {
			expect(isString('')).toBe(true);
		});

		it('should return false for number', () => {
			expect(isString(42)).toBe(false);
		});

		it('should return false for null', () => {
			expect(isString(null)).toBe(false);
		});

		it('should return false for undefined', () => {
			expect(isString(undefined)).toBe(false);
		});
	});

	describe('isNumber', () => {
		it('should return true for integer', () => {
			expect(isNumber(42)).toBe(true);
		});

		it('should return true for float', () => {
			expect(isNumber(3.14)).toBe(true);
		});

		it('should return true for 0', () => {
			expect(isNumber(0)).toBe(true);
		});

		it('should return true for NaN', () => {
			expect(isNumber(NaN)).toBe(true);
		});

		it('should return false for string', () => {
			expect(isNumber('42')).toBe(false);
		});

		it('should return false for null', () => {
			expect(isNumber(null)).toBe(false);
		});
	});

	describe('isConstructor', () => {
		it('should return true for "constructor" string', () => {
			expect(isConstructor('constructor')).toBe(true);
		});

		it('should return false for other string', () => {
			expect(isConstructor('notConstructor')).toBe(false);
		});

		it('should return false for function', () => {
			expect(isConstructor(() => {})).toBe(false);
		});
	});

	describe('isNil', () => {
		it('should return true for null', () => {
			expect(isNil(null)).toBe(true);
		});

		it('should return true for undefined', () => {
			expect(isNil(undefined)).toBe(true);
		});

		it('should return false for 0', () => {
			expect(isNil(0)).toBe(false);
		});

		it('should return false for empty string', () => {
			expect(isNil('')).toBe(false);
		});

		it('should return false for false', () => {
			expect(isNil(false)).toBe(false);
		});
	});

	describe('isEmpty', () => {
		it('should return true for empty array', () => {
			expect(isEmpty([])).toBe(true);
		});

		it('should return true for null', () => {
			expect(isEmpty(null)).toBe(true);
		});

		it('should return true for undefined', () => {
			expect(isEmpty(undefined)).toBe(true);
		});

		it('should return false for non-empty array', () => {
			expect(isEmpty([1, 2, 3])).toBe(false);
		});

		it('should return false for string with length', () => {
			expect(isEmpty('hello')).toBe(false);
		});
	});

	describe('isSymbol', () => {
		it('should return true for symbol', () => {
			expect(isSymbol(Symbol('test'))).toBe(true);
		});

		it('should return true for Symbol.iterator', () => {
			expect(isSymbol(Symbol.iterator)).toBe(true);
		});

		it('should return false for string', () => {
			expect(isSymbol('symbol')).toBe(false);
		});

		it('should return false for number', () => {
			expect(isSymbol(42)).toBe(false);
		});

		it('should return false for null', () => {
			expect(isSymbol(null)).toBe(false);
		});
	});
});

describe('AppConsoleLogger', () => {
	let stdoutSpy: jest.SpyInstance;
	let stderrSpy: jest.SpyInstance;

	beforeEach(() => {
		stdoutSpy = jest.spyOn(process.stdout, 'write').mockImplementation(() => true);
		stderrSpy = jest.spyOn(process.stderr, 'write').mockImplementation(() => true);
		(correlator.getId as jest.Mock).mockReturnValue('test-correlation-id');
	});

	afterEach(() => {
		jest.clearAllMocks();
	});

	describe('constructor overloads', () => {
		it('should construct with no arguments', () => {
			const logger = new AppConsoleLogger();
			expect(logger).toBeDefined();
			expect(logger.isLevelEnabled('log')).toBe(true);
		});

		it('should construct with string context', () => {
			const logger = new AppConsoleLogger('TestContext');
			expect(logger).toBeDefined();
			logger.log('hello');
			expect(stdoutSpy).toHaveBeenCalled();
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('[TestContext]');
		});

		it('should construct with options object', () => {
			const logger = new AppConsoleLogger({ logLevels: ['error'] });
			expect(logger.isLevelEnabled('error')).toBe(true);
			expect(logger.isLevelEnabled('log')).toBe(false);
		});

		it('should construct with context string and options', () => {
			const logger = new AppConsoleLogger('MyContext', { logLevels: ['warn', 'error'] });
			expect(logger.isLevelEnabled('warn')).toBe(true);
			expect(logger.isLevelEnabled('log')).toBe(false);
			logger.warn('test warn');
			expect(stdoutSpy).toHaveBeenCalled();
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('[MyContext]');
		});

		it('should construct with options containing context property', () => {
			const logger = new AppConsoleLogger({ context: 'OptionsContext' });
			logger.log('test');
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('[OptionsContext]');
		});

		it('should default prefix to Nest', () => {
			const logger = new AppConsoleLogger();
			logger.log('test');
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('[Nest]');
		});

		it('should use custom prefix from options', () => {
			const logger = new AppConsoleLogger({ prefix: 'MyApp' });
			logger.log('test');
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('[MyApp]');
		});

		it('should disable colors when json mode is true', () => {
			const logger = new AppConsoleLogger({ json: true });
			expect(logger['options'].colors).toBe(false);
		});
	});

	describe('log method', () => {
		it('should write to stdout', () => {
			const logger = new AppConsoleLogger();
			logger.log('test message');
			expect(stdoutSpy).toHaveBeenCalledTimes(1);
			expect(stderrSpy).not.toHaveBeenCalled();
		});

		it('should include message in output', () => {
			const logger = new AppConsoleLogger();
			logger.log('hello world');
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('hello world');
		});

		it('should include correlation id in output', () => {
			const logger = new AppConsoleLogger();
			logger.log('test');
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('test-correlation-id');
		});

		it('should use fallback UUID when correlator returns undefined', () => {
			(correlator.getId as jest.Mock).mockReturnValue(undefined);
			const logger = new AppConsoleLogger();
			logger.log('test');
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('fallback-uuid');
		});

		it('should not write when log level is disabled', () => {
			const logger = new AppConsoleLogger({ logLevels: ['error'] });
			logger.log('test');
			expect(stdoutSpy).not.toHaveBeenCalled();
		});

		it('should include context from constructor when no inline context given', () => {
			const logger = new AppConsoleLogger('CtxA');
			logger.log('msg');
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('[CtxA]');
		});

		it('should use inline context over constructor context', () => {
			const logger = new AppConsoleLogger('CtxA');
			logger.log('msg', 'CtxB');
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('[CtxB]');
			expect(output).not.toContain('[CtxA]');
		});

		it('should handle object message', () => {
			const logger = new AppConsoleLogger();
			logger.log({ key: 'value' });
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('Object(1)');
		});

		it('should handle array message', () => {
			const logger = new AppConsoleLogger();
			logger.log([1, 2, 3]);
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('Array(3)');
		});

		it('should handle function message that returns a value', () => {
			const logger = new AppConsoleLogger();
			logger.log(() => 'from function');
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('from function');
		});

		it('should handle class message by using class name', () => {
			const logger = new AppConsoleLogger();
			class MyClass {}
			logger.log(MyClass);
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('MyClass');
		});
	});

	describe('error method', () => {
		it('should write to stderr', () => {
			const logger = new AppConsoleLogger();
			logger.error('error message');
			expect(stderrSpy).toHaveBeenCalled();
		});

		it('should include message in stderr output', () => {
			const logger = new AppConsoleLogger();
			logger.error('something failed');
			const output = String(stderrSpy.mock.calls[0][0]);
			expect(output).toContain('something failed');
		});

		it('should not write when error level is disabled', () => {
			const logger = new AppConsoleLogger({ logLevels: ['log'] });
			logger.error('test');
			expect(stderrSpy).not.toHaveBeenCalled();
		});

		it('should print stack trace when stack is provided', () => {
			const logger = new AppConsoleLogger();
			const stack = 'Error: test\n    at Object.<anonymous> (file.ts:1:1)';
			logger.error('msg', stack);
			const allCalls = stderrSpy.mock.calls.map((c) => String(c[0])).join('');
			expect(allCalls).toContain('Error: test');
		});

		it('should handle error with context string (no stack format)', () => {
			const logger = new AppConsoleLogger();
			logger.error('msg', 'SomeContext');
			const output = String(stderrSpy.mock.calls[0][0]);
			expect(output).toContain('msg');
		});

		it('should handle error with message, stack, and context', () => {
			const logger = new AppConsoleLogger();
			const stack = 'Error: fail\n    at Object.<anonymous> (file.ts:10:5)';
			logger.error('msg', stack, 'ErrorContext');
			expect(stderrSpy).toHaveBeenCalled();
		});
	});

	describe('warn method', () => {
		it('should write to stdout', () => {
			const logger = new AppConsoleLogger();
			logger.warn('warning message');
			expect(stdoutSpy).toHaveBeenCalled();
		});

		it('should include message in output', () => {
			const logger = new AppConsoleLogger();
			logger.warn('be careful');
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('be careful');
		});

		it('should not write when warn level is disabled', () => {
			const logger = new AppConsoleLogger({ logLevels: ['error'] });
			logger.warn('test');
			expect(stdoutSpy).not.toHaveBeenCalled();
		});

		it('should use inline context', () => {
			const logger = new AppConsoleLogger();
			logger.warn('msg', 'WarnCtx');
			const output = String(stdoutSpy.mock.calls[0][0]);
			expect(output).toContain('[WarnCtx]');
		});
	});

	describe('debug method', () => {
		it('should write to stdout', () => {
			const logger = new AppConsoleLogger();
			logger.debug('debug message');
